#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *arr = (long long*)malloc(N * sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &arr[i]);
        printf("%lld\n", arr[N/2]);
        free(arr);
    }
    return 0;
}

